#!/bin/bash\n\n# Agent Feed Architecture Validation Script\n# Validates the complete system architecture setup\n\nset -euo pipefail\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\n# Logging functions\nlog_info() {\n    echo -e \"${BLUE}[INFO]${NC} $1\"\n}\n\nlog_success() {\n    echo -e \"${GREEN}[SUCCESS]${NC} $1\"\n}\n\nlog_warning() {\n    echo -e \"${YELLOW}[WARNING]${NC} $1\"\n}\n\nlog_error() {\n    echo -e \"${RED}[ERROR]${NC} $1\"\n}\n\n# Validation results\nPASSED_CHECKS=0\nFAILED_CHECKS=0\nWARNING_CHECKS=0\n\n# Check if file exists\ncheck_file() {\n    local file=\"$1\"\n    local description=\"$2\"\n    \n    if [ -f \"$file\" ]; then\n        log_success \"$description: $file\"\n        ((PASSED_CHECKS++))\n        return 0\n    else\n        log_error \"$description: $file (missing)\"\n        ((FAILED_CHECKS++))\n        return 1\n    fi\n}\n\n# Check if directory exists\ncheck_directory() {\n    local dir=\"$1\"\n    local description=\"$2\"\n    \n    if [ -d \"$dir\" ]; then\n        log_success \"$description: $dir\"\n        ((PASSED_CHECKS++))\n        return 0\n    else\n        log_error \"$description: $dir (missing)\"\n        ((FAILED_CHECKS++))\n        return 1\n    fi\n}\n\n# Check file content\ncheck_file_content() {\n    local file=\"$1\"\n    local pattern=\"$2\"\n    local description=\"$3\"\n    \n    if [ -f \"$file\" ] && grep -q \"$pattern\" \"$file\"; then\n        log_success \"$description\"\n        ((PASSED_CHECKS++))\n        return 0\n    else\n        log_error \"$description (pattern not found: $pattern)\"\n        ((FAILED_CHECKS++))\n        return 1\n    fi\n}\n\n# Validate project structure\nvalidate_project_structure() {\n    log_info \"Validating project structure...\"\n    \n    # Root directories\n    check_directory \"src\" \"Source code directory\"\n    check_directory \"tests\" \"Tests directory\"\n    check_directory \"docs\" \"Documentation directory\"\n    check_directory \"infrastructure\" \"Infrastructure directory\"\n    check_directory \"scripts\" \"Scripts directory\"\n    check_directory \"config\" \"Configuration directory\"\n    \n    # Source subdirectories\n    check_directory \"src/api\" \"API source directory\"\n    check_directory \"src/agents\" \"Agents source directory\"\n    check_directory \"src/auth\" \"Authentication source directory\"\n    check_directory \"src/database\" \"Database source directory\"\n    check_directory \"src/websocket\" \"WebSocket source directory\"\n    check_directory \"src/monitoring\" \"Monitoring source directory\"\n    check_directory \"src/utils\" \"Utilities source directory\"\n    \n    # Infrastructure subdirectories\n    check_directory \"infrastructure/docker\" \"Docker infrastructure directory\"\n    check_directory \"infrastructure/kubernetes\" \"Kubernetes infrastructure directory\"\n    check_directory \"infrastructure/nginx\" \"Nginx infrastructure directory\"\n}\n\n# Validate configuration files\nvalidate_configuration() {\n    log_info \"Validating configuration files...\"\n    \n    # TypeScript configuration\n    check_file \"tsconfig.json\" \"TypeScript configuration\"\n    check_file_content \"tsconfig.json\" \"ES2022\" \"TypeScript target ES2022\"\n    check_file_content \"tsconfig.json\" \"strict\" \"TypeScript strict mode\"\n    \n    # Jest configuration\n    check_file \"jest.config.js\" \"Jest configuration\"\n    check_file_content \"jest.config.js\" \"coverage\" \"Jest coverage configuration\"\n    \n    # ESLint configuration\n    check_file \"eslint.config.js\" \"ESLint configuration\"\n    check_file_content \"eslint.config.js\" \"typescript\" \"ESLint TypeScript support\"\n    \n    # Environment configuration\n    check_file \".env.example\" \"Environment template\"\n    check_file_content \".env.example\" \"POSTGRES_URL\" \"Database configuration\"\n    check_file_content \".env.example\" \"REDIS_URL\" \"Redis configuration\"\n    check_file_content \".env.example\" \"JWT_SECRET\" \"JWT configuration\"\n}\n\n# Validate Docker setup\nvalidate_docker() {\n    log_info \"Validating Docker setup...\"\n    \n    # Docker Compose\n    check_file \"infrastructure/docker/docker-compose.yml\" \"Docker Compose configuration\"\n    check_file_content \"infrastructure/docker/docker-compose.yml\" \"postgres:15-alpine\" \"PostgreSQL service\"\n    check_file_content \"infrastructure/docker/docker-compose.yml\" \"redis:7-alpine\" \"Redis service\"\n    check_file_content \"infrastructure/docker/docker-compose.yml\" \"agent-feed-network\" \"Custom network\"\n    \n    # Dockerfiles\n    check_file \"infrastructure/docker/Dockerfile.base\" \"Base Dockerfile\"\n    check_file \"infrastructure/docker/Dockerfile.api-gateway\" \"API Gateway Dockerfile\"\n    check_file \"infrastructure/docker/Dockerfile.agent-management\" \"Agent Management Dockerfile\"\n    check_file \"infrastructure/docker/Dockerfile.feed-processing\" \"Feed Processing Dockerfile\"\n    check_file \"infrastructure/docker/Dockerfile.user-management\" \"User Management Dockerfile\"\n    check_file \"infrastructure/docker/Dockerfile.websocket\" \"WebSocket Dockerfile\"\n}\n\n# Validate Kubernetes setup\nvalidate_kubernetes() {\n    log_info \"Validating Kubernetes setup...\"\n    \n    # Kubernetes manifests\n    check_file \"infrastructure/kubernetes/namespace.yaml\" \"Kubernetes namespace\"\n    check_file \"infrastructure/kubernetes/configmap.yaml\" \"Kubernetes ConfigMap\"\n    check_file \"infrastructure/kubernetes/secrets.yaml\" \"Kubernetes Secrets\"\n    check_file \"infrastructure/kubernetes/database.yaml\" \"Database deployment\"\n    check_file \"infrastructure/kubernetes/services.yaml\" \"Services deployment\"\n    check_file \"infrastructure/kubernetes/ingress.yaml\" \"Ingress configuration\"\n    check_file \"infrastructure/kubernetes/monitoring.yaml\" \"Monitoring setup\"\n    \n    # Kubernetes content validation\n    check_file_content \"infrastructure/kubernetes/namespace.yaml\" \"agent-feed\" \"Namespace definition\"\n    check_file_content \"infrastructure/kubernetes/services.yaml\" \"api-gateway\" \"API Gateway service\"\n    check_file_content \"infrastructure/kubernetes/monitoring.yaml\" \"prometheus\" \"Prometheus monitoring\"\n}\n\n# Validate Nginx setup\nvalidate_nginx() {\n    log_info \"Validating Nginx setup...\"\n    \n    # Nginx configuration\n    check_file \"infrastructure/nginx/nginx.conf\" \"Nginx main configuration\"\n    check_file \"infrastructure/nginx/conf.d/default.conf\" \"Nginx default configuration\"\n    \n    # Nginx content validation\n    check_file_content \"infrastructure/nginx/nginx.conf\" \"upstream\" \"Upstream configuration\"\n    check_file_content \"infrastructure/nginx/conf.d/default.conf\" \"proxy_pass\" \"Proxy configuration\"\n    check_file_content \"infrastructure/nginx/conf.d/default.conf\" \"websocket\" \"WebSocket support\"\n}\n\n# Validate CI/CD setup\nvalidate_cicd() {\n    log_info \"Validating CI/CD setup...\"\n    \n    # GitHub Actions\n    check_file \".github/workflows/ci-cd.yml\" \"CI/CD workflow\"\n    check_file_content \".github/workflows/ci-cd.yml\" \"test\" \"Test job\"\n    check_file_content \".github/workflows/ci-cd.yml\" \"build\" \"Build job\"\n    check_file_content \".github/workflows/ci-cd.yml\" \"deploy\" \"Deploy job\"\n    check_file_content \".github/workflows/ci-cd.yml\" \"security\" \"Security scan\"\n}\n\n# Validate source code structure\nvalidate_source_code() {\n    log_info \"Validating source code structure...\"\n    \n    # Utility modules\n    check_file \"src/utils/config.js\" \"Configuration module\"\n    check_file \"src/utils/logger.js\" \"Logging module\"\n    check_file \"src/utils/health-check.js\" \"Health check module\"\n    \n    # Configuration content validation\n    check_file_content \"src/utils/config.js\" \"joi\" \"Configuration validation\"\n    check_file_content \"src/utils/logger.js\" \"winston\" \"Logging framework\"\n    check_file_content \"src/utils/health-check.js\" \"HealthCheck\" \"Health check class\"\n}\n\n# Validate scripts\nvalidate_scripts() {\n    log_info \"Validating scripts...\"\n    \n    # Setup script\n    check_file \"scripts/setup-dev.sh\" \"Development setup script\"\n    \n    # Check if setup script is executable\n    if [ -x \"scripts/setup-dev.sh\" ]; then\n        log_success \"Setup script is executable\"\n        ((PASSED_CHECKS++))\n    else\n        log_warning \"Setup script is not executable\"\n        ((WARNING_CHECKS++))\n    fi\n    \n    # Script content validation\n    check_file_content \"scripts/setup-dev.sh\" \"docker-compose\" \"Docker setup\"\n    check_file_content \"scripts/setup-dev.sh\" \"npm\" \"NPM setup\"\n}\n\n# Validate documentation\nvalidate_documentation() {\n    log_info \"Validating documentation...\"\n    \n    # Architecture documentation\n    check_file \"docs/architecture/SERVICE_ARCHITECTURE.md\" \"Service architecture documentation\"\n    \n    # Documentation content validation\n    check_file_content \"docs/architecture/SERVICE_ARCHITECTURE.md\" \"microservices\" \"Microservices architecture\"\n    check_file_content \"docs/architecture/SERVICE_ARCHITECTURE.md\" \"PostgreSQL\" \"Database documentation\"\n    check_file_content \"docs/architecture/SERVICE_ARCHITECTURE.md\" \"Redis\" \"Cache documentation\"\n}\n\n# Validate package.json\nvalidate_package_json() {\n    log_info \"Validating package.json...\"\n    \n    check_file \"package.json\" \"Package configuration\"\n    check_file_content \"package.json\" \"express\" \"Express.js dependency\"\n    check_file_content \"package.json\" \"jest\" \"Jest testing framework\"\n    check_file_content \"package.json\" \"eslint\" \"ESLint linting\"\n    check_file_content \"package.json\" \"typescript\" \"TypeScript support\"\n    \n    # Check for required scripts\n    check_file_content \"package.json\" \"\\\"test\\\"\" \"Test script\"\n    check_file_content \"package.json\" \"\\\"build\\\"\" \"Build script\"\n    check_file_content \"package.json\" \"\\\"lint\\\"\" \"Lint script\"\n}\n\n# Check Docker availability\ncheck_docker_availability() {\n    log_info \"Checking Docker availability...\"\n    \n    if command -v docker >/dev/null 2>&1; then\n        log_success \"Docker is available\"\n        ((PASSED_CHECKS++))\n        \n        if docker info >/dev/null 2>&1; then\n            log_success \"Docker daemon is running\"\n            ((PASSED_CHECKS++))\n        else\n            log_warning \"Docker daemon is not running\"\n            ((WARNING_CHECKS++))\n        fi\n    else\n        log_error \"Docker is not installed\"\n        ((FAILED_CHECKS++))\n    fi\n    \n    if command -v docker-compose >/dev/null 2>&1; then\n        log_success \"Docker Compose is available\"\n        ((PASSED_CHECKS++))\n    else\n        log_error \"Docker Compose is not installed\"\n        ((FAILED_CHECKS++))\n    fi\n}\n\n# Check Node.js setup\ncheck_nodejs_setup() {\n    log_info \"Checking Node.js setup...\"\n    \n    if command -v node >/dev/null 2>&1; then\n        local node_version\n        node_version=$(node --version | cut -d'v' -f2 | cut -d'.' -f1)\n        \n        if [ \"$node_version\" -ge 18 ]; then\n            log_success \"Node.js version $(node --version) is compatible\"\n            ((PASSED_CHECKS++))\n        else\n            log_error \"Node.js version $(node --version) is too old (requires 18+)\"\n            ((FAILED_CHECKS++))\n        fi\n    else\n        log_error \"Node.js is not installed\"\n        ((FAILED_CHECKS++))\n    fi\n    \n    if command -v npm >/dev/null 2>&1; then\n        log_success \"NPM is available\"\n        ((PASSED_CHECKS++))\n    else\n        log_error \"NPM is not installed\"\n        ((FAILED_CHECKS++))\n    fi\n}\n\n# Generate validation report\ngenerate_report() {\n    echo -e \"${BLUE}\"\n    echo \"==========================================\"\n    echo \"    Architecture Validation Report      \"\n    echo \"==========================================\"\n    echo -e \"${NC}\"\n    \n    echo \"Total Checks: $((PASSED_CHECKS + FAILED_CHECKS + WARNING_CHECKS))\"\n    echo -e \"${GREEN}Passed: ${PASSED_CHECKS}${NC}\"\n    echo -e \"${RED}Failed: ${FAILED_CHECKS}${NC}\"\n    echo -e \"${YELLOW}Warnings: ${WARNING_CHECKS}${NC}\"\n    echo \"\"\n    \n    if [ $FAILED_CHECKS -eq 0 ]; then\n        log_success \"Architecture validation PASSED!\"\n        echo \"\"\n        log_info \"Next steps:\"\n        echo \"  1. Run: ./scripts/setup-dev.sh\"\n        echo \"  2. Start development: npm run dev\"\n        echo \"  3. Run tests: npm test\"\n        return 0\n    else\n        log_error \"Architecture validation FAILED!\"\n        echo \"\"\n        log_info \"Please fix the issues above and run validation again.\"\n        return 1\n    fi\n}\n\n# Main validation function\nmain() {\n    echo -e \"${BLUE}\"\n    echo \"==========================================\"\n    echo \"  Agent Feed Architecture Validation    \"\n    echo \"==========================================\"\n    echo -e \"${NC}\"\n    \n    # Change to project root\n    cd \"$(dirname \"$0\")/..\"\n    \n    # Run all validations\n    validate_project_structure\n    validate_configuration\n    validate_docker\n    validate_kubernetes\n    validate_nginx\n    validate_cicd\n    validate_source_code\n    validate_scripts\n    validate_documentation\n    validate_package_json\n    check_docker_availability\n    check_nodejs_setup\n    \n    # Generate report\n    generate_report\n}\n\n# Handle script interruption\ntrap 'log_error \"Validation interrupted\"; exit 1' INT TERM\n\n# Run main function\nmain \"$@\""